import json
import time
import pytest


# ─── REQ-001: end-to-end dispatch on all four surfaces ─────────────────────


def test_send_message_with_mention_dispatches_all_four_surfaces_end_to_end(
    db, http_client, seeded_channel, member_with_dnd
):
    """REQ-001: POST /api/messages with @-mention triggers concurrent
    delivery on push / in-app banner / sound / unread badge. Verified by
    inspecting both API response (delivery report) and persistent state
    (member_counters in Postgres)."""
    member_with_dnd("U2")
    resp = http_client.post(
        "/api/messages",
        json={
            "author": "U1",
            "channel": seeded_channel,
            "text": "hey @U2 please look",
            "mention_ids": ["U2"],
        },
    )
    assert resp.status_code == 201
    body = resp.json()
    assert body["delivered"] is True
    assert set(body["surfaces_fired"]) == {
        "PushSurface",
        "InAppBannerSurface",
        "SoundSurface",
        "UnreadBadgeSurface",
    }

    # Cross-check at DB boundary (interface-drift catch).
    row = db.execute(
        "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
        ["U2"],
    ).fetchone()
    assert row[0] == 1
    assert row[1] == 1


# ─── REQ-002 (DND silence) at integration boundary ────────────────────────


def test_mention_under_dnd_increments_badge_but_no_external_dispatch_observed(
    db, http_client, seeded_channel, member_with_dnd
):
    """REQ-002: under DND, push/banner/sound MUST not fire (no external
    dispatch observed via the surface log), but the unread badge & count
    increment silently."""
    member_with_dnd("U2", manual_on=True)
    http_client.post(
        "/api/messages",
        json={"author": "U1", "channel": seeded_channel, "text": "ping @U2", "mention_ids": ["U2"]},
    )
    # Verify external surfaces silent.
    log = http_client.get("/api/_internal/surface_log?member=U2").json()
    assert "PushSurface" not in log["fired"]
    assert "InAppBannerSurface" not in log["fired"]
    assert "SoundSurface" not in log["fired"]
    # Counters still incremented.
    row = db.execute(
        "SELECT unread_badge_count FROM member_counters WHERE member_id = %s", ["U2"]
    ).fetchone()
    assert row[0] == 1


# ─── REQ-005: edit adding a new mention dispatches only to the new recipient


def test_edit_adding_mention_dispatches_new_recipient_only(
    db, http_client, seeded_channel, member_with_dnd
):
    """REQ-005: an edit that adds U3 to an existing message originally
    mentioning U2 dispatches to U3 only (not a re-dispatch to U2)."""
    member_with_dnd("U2")
    member_with_dnd("U3")

    create_resp = http_client.post(
        "/api/messages",
        json={"author": "U1", "channel": seeded_channel, "text": "@U2", "mention_ids": ["U2"]},
    )
    msg_id = create_resp.json()["id"]

    # Reset surface log to isolate edit effect.
    http_client.delete(f"/api/_internal/surface_log?member=U2")
    http_client.delete(f"/api/_internal/surface_log?member=U3")

    edit_resp = http_client.patch(
        f"/api/messages/{msg_id}",
        json={"text": "@U2 @U3", "mention_ids": ["U2", "U3"]},
    )
    assert edit_resp.status_code == 200

    log_u2 = http_client.get("/api/_internal/surface_log?member=U2").json()
    log_u3 = http_client.get("/api/_internal/surface_log?member=U3").json()
    assert log_u2["fired"] == []  # no re-dispatch to existing mention
    assert set(log_u3["fired"]) >= {"PushSurface", "InAppBannerSurface", "SoundSurface", "UnreadBadgeSurface"}


# ─── REQ-006: delete retracts in-app banner over realtime channel ──────────


def test_delete_message_retracts_in_app_banner_via_realtime_channel(
    db, http_client, seeded_channel, member_with_dnd, realtime_subscriber
):
    """REQ-006: DELETE /api/messages/:id publishes a banner-retraction event
    over the realtime pub/sub channel (REAL Redis container) for the
    in-app surface, without touching push or counters."""
    member_with_dnd("U2")
    create = http_client.post(
        "/api/messages",
        json={"author": "U1", "channel": seeded_channel, "text": "@U2", "mention_ids": ["U2"]},
    )
    msg_id = create.json()["id"]
    # Drain initial subscribe-ack frame.
    realtime_subscriber.get_message(timeout=1.0)

    resp = http_client.delete(f"/api/messages/{msg_id}")
    assert resp.status_code == 204

    # Wait for the retraction event on the pubsub.
    deadline = time.time() + 5.0
    event = None
    while time.time() < deadline:
        msg = realtime_subscriber.get_message(timeout=0.5)
        if msg and msg.get("type") == "message":
            event = json.loads(msg["data"])
            break
    assert event is not None, "no retraction event received within 5s"
    assert event["kind"] == "in_app_banner_retract"
    assert event["msg_id"] == msg_id
    assert event["target_member"] == "U2"

    # Counters unchanged (REQ-006: non-retractable surfaces left in pre-deletion state).
    row = db.execute(
        "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
        ["U2"],
    ).fetchone()
    assert row[0] == 1
    assert row[1] == 1


# ─── REQ-007: DND end does not trigger resurfacing dispatch ────────────────


def test_dnd_window_expiry_does_not_trigger_resurfacing_dispatch(
    db, http_client, seeded_channel, member_with_dnd
):
    """REQ-007: at DND deactivation, accumulated mentions SHALL NOT fire
    retroactive push/banner/sound. Observed via surface log over the
    deactivation transition."""
    member_with_dnd("U2", manual_on=True)
    # Drop two mentions during DND.
    for txt in ["@U2 ping1", "@U2 ping2"]:
        http_client.post(
            "/api/messages",
            json={"author": "U1", "channel": seeded_channel, "text": txt, "mention_ids": ["U2"]},
        )
    # Reset log so we only see what DND-end fires.
    http_client.delete("/api/_internal/surface_log?member=U2")

    resp = http_client.put("/api/members/U2/dnd", json={"manual_on": False})
    assert resp.status_code == 200

    log = http_client.get("/api/_internal/surface_log?member=U2").json()
    assert log["fired"] == []  # NOTHING fired at deactivation
    row = db.execute(
        "SELECT unread_badge_count, unread_mention_count FROM member_counters WHERE member_id = %s",
        ["U2"],
    ).fetchone()
    assert row[0] == 2
    assert row[1] == 2


# ─── REQ-002 extension: broadcast under DND obeys silence ──────────────────


def test_broadcast_at_channel_under_dnd_does_not_dispatch_push(
    db, http_client, seeded_channel, member_with_dnd
):
    """REQ-002 extension: broadcast @channel intent does NOT override DND.
    Verifies the silence rule applies to broadcast across the integration
    boundary (resolver → filter → dispatcher → surface log)."""
