    http_client.post(
        "/api/messages",
        json={
            "author": "U1",
            "channel": seeded_channel,
            "text": "@channel announcement",
            "mention_ids": [],
            "mention_kind": "channel",
        },
    )
    log_u2 = http_client.get("/api/_internal/surface_log?member=U2").json()
    log_u3 = http_client.get("/api/_internal/surface_log?member=U3").json()
    assert "PushSurface" not in log_u2["fired"]
    assert "InAppBannerSurface" not in log_u2["fired"]
    assert "SoundSurface" not in log_u2["fired"]
    # U3 (no DND) sees the full set.
    assert {"PushSurface", "InAppBannerSurface", "SoundSurface", "UnreadBadgeSurface"} <= set(log_u3["fired"])
